package com.example.bankapp.data;

import android.content.Context;
import android.content.SharedPreferences;

import java.math.BigDecimal;

public final class AccountRepository {
    private static final String PREFS = "bank_prefs";
    private static final String KEY_BALANCE = "balance_cents";
    private final SharedPreferences prefs;

    public AccountRepository(Context context) {
        this.prefs = context.getApplicationContext().getSharedPreferences(PREFS, Context.MODE_PRIVATE);
    }

    public synchronized BigDecimal getBalance() {
        long cents = prefs.getLong(KEY_BALANCE, 0L);
        return new BigDecimal(cents).movePointLeft(2);
    }

    public synchronized void setBalance(BigDecimal amount) {
        long cents = amount.movePointRight(2).setScale(0, BigDecimal.ROUND_HALF_UP).longValueExact();
        prefs.edit().putLong(KEY_BALANCE, cents).apply();
    }

    public synchronized boolean tryApplyDelta(BigDecimal delta) {
        BigDecimal current = getBalance();
        BigDecimal next = current.add(delta);
        if (next.compareTo(BigDecimal.ZERO) < 0) return false;
        setBalance(next);
        return true;
    }
}

