package com.example.bankapp.security;

import android.util.Base64;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;

public final class SimpleSecurity {
    private SimpleSecurity() {}

    public static String hash(String input) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] out = md.digest(input.getBytes(StandardCharsets.UTF_8));
            return Base64.encodeToString(out, Base64.NO_WRAP);
        } catch (Exception e) {
            return "";
        }
    }
}

package com.example.bankapp.tx;

import android.content.Context;

import com.example.bankapp.data.AccountRepository;
import com.example.bankapp.model.Transaction;
import com.example.bankapp.security.SimpleSecurity;

import java.math.BigDecimal;
import java.util.UUID;

public final class TransactionProcessor {

    public static final class Result {
        public final boolean success;
        public final String message;
        public final Transaction transaction;

        private Result(boolean success, String message, Transaction transaction) {
            this.success = success;
            this.message = message;
            this.transaction = transaction;
        }

        public static Result ok(Transaction t) { return new Result(true, "OK", t); }
        public static Result fail(String msg) { return new Result(false, msg, null); }
    }

    private final AccountRepository repo;

    public TransactionProcessor(Context context) {
        this.repo = new AccountRepository(context);
    }

    public synchronized Result deposit(BigDecimal amount, String note) {
        if (!isValidAmount(amount)) return Result.fail("Invalid amount");
        boolean applied = repo.tryApplyDelta(amount);
        if (!applied) return Result.fail("Unable to apply deposit");
        Transaction t = new Transaction(newId("DEP", amount), Transaction.Type.DEPOSIT, amount, System.currentTimeMillis(), note);
        return Result.ok(t);
    }

    public synchronized Result withdraw(BigDecimal amount, String note) {
        if (!isValidAmount(amount)) return Result.fail("Invalid amount");
        BigDecimal delta = amount.negate();
        boolean applied = repo.tryApplyDelta(delta);
        if (!applied) return Result.fail("Insufficient funds");
        Transaction t = new Transaction(newId("WDR", amount), Transaction.Type.WITHDRAWAL, amount, System.currentTimeMillis(), note);
        return Result.ok(t);
    }

    public synchronized Result transferOut(BigDecimal amount, String toAccountRef, String note) {
        if (!isValidAmount(amount)) return Result.fail("Invalid amount");
        if (toAccountRef == null || toAccountRef.trim().isEmpty()) return Result.fail("Missing destination");
        BigDecimal delta = amount.negate();
        boolean applied = repo.tryApplyDelta(delta);
        if (!applied) return Result.fail("Insufficient funds");
        String n = (note == null ? "" : note) + " to:" + toAccountRef;
        Transaction t = new Transaction(newId("XFR_OUT", amount), Transaction.Type.TRANSFER_OUT, amount, System.currentTimeMillis(), n);
        return Result.ok(t);
    }

    public synchronized Result transferIn(BigDecimal amount, String fromAccountRef, String note) {
        if (!isValidAmount(amount)) return Result.fail("Invalid amount");
        if (fromAccountRef == null || fromAccountRef.trim().isEmpty()) return Result.fail("Missing source");
        boolean applied = repo.tryApplyDelta(amount);
        if (!applied) return Result.fail("Unable to apply transfer");
        String n = (note == null ? "" : note) + " from:" + fromAccountRef;
        Transaction t = new Transaction(newId("XFR_IN", amount), Transaction.Type.TRANSFER_IN, amount, System.currentTimeMillis(), n);
        return Result.ok(t);
    }

    public BigDecimal getBalance() {
        return repo.getBalance();
    }

    private static boolean isValidAmount(BigDecimal amount) {
        if (amount == null) return false;
        if (amount.compareTo(BigDecimal.ZERO) <= 0) return false;
        if (amount.scale() > 2) return false;
        return true;
    }

    private static String newId(String prefix, BigDecimal amount) {
        String raw = prefix + ":" + amount.toPlainString() + ":" + System.currentTimeMillis() + ":" + UUID.randomUUID();
        return prefix + "_" + SimpleSecurity.hash(raw);
    }
}

package com.example.bankapp.ui;

import android.os.Bundle;
import android.text.InputType;
import android.view.Gravity;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.TextView;
import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import com.example.bankapp.tx.TransactionProcessor;

import java.math.BigDecimal;
import java.text.NumberFormat;
import java.util.Locale;

public class MainActivity extends AppCompatActivity {

    private TransactionProcessor processor;
    private TextView balanceView;
    private TextView statusView;
    private EditText amountInput;
    private EditText noteInput;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        processor = new TransactionProcessor(this);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(dp(16), dp(16), dp(16), dp(16));
        root.setGravity(Gravity.TOP);

        TextView title = new TextView(this);
        title.setText("Banking");
        title.setTextSize(20f);

        balanceView = new TextView(this);
        balanceView.setTextSize(18f);

        statusView = new TextView(this);
        statusView.setTextSize(14f);

        amountInput = new EditText(this);
        amountInput.setHint("Amount (e.g., 10.00)");
        amountInput.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_FLAG_DECIMAL);

        noteInput = new EditText(this);
        noteInput.setHint("Note (optional)");

        LinearLayout buttons = new LinearLayout(this);
        buttons.setOrientation(LinearLayout.HORIZONTAL);

        Button depositBtn = new Button(this);
        depositBtn.setText("Deposit");

        Button withdrawBtn = new Button(this);
        withdrawBtn.setText("Withdraw");

        buttons.addView(depositBtn, new LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f));
        buttons.addView(withdrawBtn, new LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f));

        root.addView(title);
        root.addView(space());
        root.addView(balanceView);
        root.addView(space());
        root.addView(amountInput);
        root.addView(noteInput);
        root.addView(space());
        root.addView(buttons);
        root.addView(space());
        root.addView(statusView);

        setContentView(root);

        depositBtn.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                BigDecimal amt = parseAmount(amountInput.getText().toString());
                TransactionProcessor.Result r = processor.deposit(amt, noteInput.getText().toString());
                statusView.setText(r.success ? "Deposit successful" : ("Deposit failed: " + r.message));
                refreshBalance();
            }
        });

        withdrawBtn.setOnClickListener(new View.OnClickListener() {
            @Override public void onClick(View v) {
                BigDecimal amt = parseAmount(amountInput.getText().toString());
                TransactionProcessor.Result r = processor.withdraw(amt, noteInput.getText().toString());
                statusView.setText(r.success ? "Withdrawal successful" : ("Withdrawal failed: " + r.message));
                refreshBalance();
            }
        });

        refreshBalance();
    }

    private void refreshBalance() {
        BigDecimal bal = processor.getBalance();
        NumberFormat nf = NumberFormat.getCurrencyInstance(Locale.getDefault());
        balanceView.setText("Balance: " + nf.format(bal));
    }

    private static BigDecimal parseAmount(String s) {
        try {
            if (s == null) return null;
            s = s.trim();
            if (s.isEmpty()) return null;
            BigDecimal bd = new BigDecimal(s);
            return bd.setScale(2, BigDecimal.ROUND_HALF_UP);
        } catch (Exception e) {
            return null;
        }
    }

    private View space() {
        View v = new View(this);
        v.setLayoutParams(new LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(12)));
        return v;
    }

    private int dp(int dp) {
        float d = getResources().getDisplayMetrics().density;
        return (int) (dp * d + 0.5f);
    }
}

